import{_ as t,o as a,c as r,a7 as s}from"./chunks/framework.C5fSpjcB.js";const g=JSON.parse('{"title":"Phase Chess","description":"","frontmatter":{},"headers":[],"relativePath":"en/modes/phase-chess.md","filePath":"en/modes/phase-chess.md","lastUpdated":1775394001000}'),i={name:"en/modes/phase-chess.md"};function n(l,e,o,d,h,c){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="phase-chess" tabindex="-1">Phase Chess <a class="header-anchor" href="#phase-chess" aria-label="Permalink to &quot;Phase Chess&quot;">​</a></h1><p><strong>Phase Chess</strong> is Morimens&#39; fair PvP mode. All player stats are equalized, ensuring victories are determined purely by card play skill and strategy.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Detail</th></tr></thead><tbody><tr><td>Mode Type</td><td>Competitive PvP</td></tr><tr><td>Unlock</td><td>Clear Stage <strong>3-2</strong></td></tr><tr><td>Stat Differences</td><td><strong>None</strong> -- all stats are equalized</td></tr><tr><td>Win Condition</td><td>Reduce opponent&#39;s HP to 0</td></tr></tbody></table><h2 id="fair-play-design" tabindex="-1">Fair Play Design <a class="header-anchor" href="#fair-play-design" aria-label="Permalink to &quot;Fair Play Design&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Phase Chess is designed to be completely fair. No Awakener levels, Enlightenment, Wheels of Destiny, Covenants, or Engravings affect Phase Chess stats. Winning is entirely about skill.</p></div><h2 id="rules" tabindex="-1">Rules <a class="header-anchor" href="#rules" aria-label="Permalink to &quot;Rules&quot;">​</a></h2><h3 id="energy-system" tabindex="-1">Energy System <a class="header-anchor" href="#energy-system" aria-label="Permalink to &quot;Energy System&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspect</th><th>Value</th></tr></thead><tbody><tr><td>Starting Energy</td><td><strong>3</strong></td></tr><tr><td>Energy Per Turn</td><td><strong>+1</strong></td></tr><tr><td>Maximum Energy</td><td><strong>10</strong></td></tr></tbody></table><p>Energy in Phase Chess replaces Arithmetica and follows its own rules:</p><ul><li>You begin with 3 energy on the first turn.</li><li>Each subsequent turn, you gain +1 maximum energy (Turn 2 = 4, Turn 3 = 5, etc.).</li><li>Energy caps at <strong>10</strong> per turn.</li></ul><h3 id="card-draw" tabindex="-1">Card Draw <a class="header-anchor" href="#card-draw" aria-label="Permalink to &quot;Card Draw&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspect</th><th>Value</th></tr></thead><tbody><tr><td>Cards Drawn Per Turn</td><td><strong>5</strong></td></tr><tr><td>Maximum Hand Size</td><td><strong>10</strong></td></tr></tbody></table><ul><li>You draw 5 cards at the start of each turn.</li><li>Your hand can hold a maximum of 10 cards. Excess cards drawn beyond 10 are discarded.</li></ul><h3 id="no-stat-differences" tabindex="-1">No Stat Differences <a class="header-anchor" href="#no-stat-differences" aria-label="Permalink to &quot;No Stat Differences&quot;">​</a></h3><p>All participants in Phase Chess have:</p><ul><li>Equalized ATK, DEF, and CON stats.</li><li>No equipment bonuses (Wheels, Covenants, Engravings are ignored).</li><li>No Enlightenment bonuses.</li><li>Card effects function at their base values.</li></ul><h2 id="strategy-tips" tabindex="-1">Strategy Tips <a class="header-anchor" href="#strategy-tips" aria-label="Permalink to &quot;Strategy Tips&quot;">​</a></h2><ol><li><strong>Energy curve</strong> -- Early turns have limited energy. Play efficient low-cost cards early; save powerful plays for later turns when energy is higher.</li><li><strong>Hand management</strong> -- With a draw of 5 and hand limit of 10, plan which cards to hold and which to play each turn.</li><li><strong>Card knowledge</strong> -- Since stats are equalized, knowing all card effects and their interactions is the primary competitive advantage.</li><li><strong>Realm matchups</strong> -- Different realm strategies have different strengths in PvP. Learn the matchup dynamics.</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Phase Chess unlocks after clearing Stage 3-2. Progress through the main story to access this mode.</p></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./combat.html">Combat System</a></li><li><a href="./../cards/">Card System</a></li><li><a href="./../cards/deckbuilding.html">Deckbuilding Guide</a></li></ul>',22)])])}const m=t(i,[["render",n]]);export{g as __pageData,m as default};
